// Store original request
msg.originalTrinoRequest = msg.data;

// Build Keycloak token request
const tokenUrl = env.get('FACIS_KEYCLOAK_URL') || 'https://identity.facis.cloud/realms/facis/protocol/openid-connect/token';
const clientId = env.get('FACIS_OIDC_CLIENT_ID') || 'trino';
const clientSecret = env.get('FACIS_OIDC_CLIENT_SECRET') || '';
const username = env.get('FACIS_TRINO_USER') || 'admin';
const password = env.get('FACIS_TRINO_PASSWORD') || '';

msg.url = tokenUrl;
msg.method = 'POST';
msg.headers = { 'Content-Type': 'application/x-www-form-urlencoded' };
msg.payload = `grant_type=password&client_id=${clientId}&client_secret=${clientSecret}&username=${username}&password=${password}&scope=openid`;

return msg;

const token = msg.payload?.access_token;
if (!token) {
    msg.data = {
        topic: 'error',
        recordDetails: { message: 'Failed to authenticate with Keycloak for Trino access' }
    };
    msg._socketId = msg.originalTrinoRequest?.session?._socketId;
    return msg;
}

const trinoHost = env.get('FACIS_TRINO_HOST') || '212.132.83.150';
const trinoPort = env.get('FACIS_TRINO_PORT') || '8443';
const queryType = msg.originalTrinoRequest?.recordDetails?.queryType || 'kpi-summary';
const params = msg.originalTrinoRequest?.recordDetails?.params || {};
const startTs = params.start_ts || new Date(Date.now() - 7*24*60*60*1000).toISOString();
const endTs = params.end_ts || new Date().toISOString();

let sql = '';
switch(queryType) {
    case 'kpi-summary':
        sql = `SELECT \n            AVG(net_grid_kw) as avg_net_grid,\n            AVG(avg_generation_kw) as avg_pv_generation,\n            SUM(estimated_hourly_cost_eur) as total_cost\n        FROM gold.net_grid_hourly\n        WHERE hour >= from_iso8601_timestamp('${startTs}')\n          AND hour < from_iso8601_timestamp('${endTs}')`;
        break;
    default:
        sql = msg.originalTrinoRequest?.recordDetails?.sql || 'SELECT 1';
}

msg.url = `https://${trinoHost}:${trinoPort}/v1/statement`;
msg.method = 'POST';
msg.headers = {
    'Authorization': 'Bearer ' + token,
    'Content-Type': 'text/plain',
    'X-Trino-User': env.get('FACIS_TRINO_USER') || 'admin',
    'X-Trino-Catalog': 'hive',
    'X-Trino-Schema': 'default'
};
msg.payload = sql;
msg.trinoQueryType = queryType;

return msg;

const queryType = msg.trinoQueryType;
const data = msg.payload;

if (msg.statusCode >= 400 || !data) {
    msg.data = {
        topic: 'error',
        recordDetails: { message: 'Trino query failed' }
    };
    msg._socketId = msg.originalTrinoRequest?.session?._socketId;
    return msg;
}

let result = {};
try {
    if (data.data && data.columns) {
        const cols = data.columns.map(c => c.name);
        const rows = data.data.map(row => {
            let obj = {};
            row.forEach((v, i) => { obj[cols[i]] = v; });
            return obj;
        });
        result = rows;
    }
} catch(e) {
    result = { error: e.message };
}

if (queryType === 'kpi-summary' && Array.isArray(result) && result.length > 0) {
    const row = result[0];
    msg.data = {
        topic: 'kpi.update',
        recordDetails: {
            netGrid: row.avg_net_grid,
            pvGeneration: row.avg_pv_generation,
            dailyCost: row.total_cost
        }
    };
} else {
    msg.data = {
        topic: 'trino.result',
        recordDetails: { data: result }
    };
}

msg._socketId = msg.originalTrinoRequest?.session?._socketId;
return msg;
